import numpy as np

class Board:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=object)
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for row in range(3):
            for col in range(row % 2, 8, 2):
                self.board[row, col] = Piece("white", (row, col))
        for row in range(5, 8):
            for col in range(row % 2, 8, 2):
                self.board[row, col] = Piece("black", (row, col))

    def print_board(self):
        # Print the board with pieces
        for row in range(8):
            for col in range(8):
                if self.board[row, col]:
                    print(f"{self.board[row, col].symbol} ", end="")
                else:
                    print(". ", end="")
            print()

    def make_move(self, player, move):
        # Parse the move
        start = move[0:2]
        end = move[3:]
        start_row, start_col = self.get_position(start)
        end_row, end_col = self.get_position(end)

        piece = self.board[start_row, start_col]
        if piece and piece.color == player.color:
            valid_moves = self.get_valid_moves(piece, player)
            if (end_row, end_col) in valid_moves:
                if abs(end_row - start_row) > 1:
                    # Capture move
                    captured_piece = self.board[(start_row + end_row) // 2, (start_col + end_col) // 2]
                    self.remove_piece((start_row + end_row) // 2, (start_col + end_col) // 2)
                self.move_piece(piece, end_row, end_col)
                if abs(end_row - start_row) == 2:
                    piece.king()
                return True
        return False

    def check_win(self):
        # Check if the game is won
        white_pieces = np.count_nonzero(self.board == 'w')
        black_pieces = np.count_nonzero(self.board == 'b')
        if white_pieces == 0:
            return "Black wins"
        elif black_pieces == 0:
            return "White wins"

    def get_position(self, pos):
        # Convert position to row and column
        col = ord(pos[0]) - ord('A')
        row = int(pos[1]) - 1
        return row, col

    def move_piece(self, piece, end_row, end_col):
        # Move a piece to the new position
        self.board[end_row, end_col] = piece
        self.board[piece.row, piece.col] = None
        piece.update_position(end_row, end_col)

    def remove_piece(self, row, col):
        # Remove a piece from the board
        piece = self.board[row, col]
        if piece:
            del self.board[row, col]

    def get_valid_moves(self, piece, player):
        # Get all valid moves for a piece
        valid_moves = []
        directions = [(1, 1), (-1, -1)]
        if piece.king or player.color == "white":
            directions.append((-1, 1))
        if piece.king or player.color == "black":
            directions.append((1, -1))

        for d in directions:
            new_row = piece.row + d[0]
            new_col = piece.col + d[1]

            if self.is_valid_position(new_row, new_col):
                if not self.board[new_row, new_col]:
                    valid_moves.append((new_row, new_col))
                elif self.board[new_row, new_col].color != player.color:
                    capture_row = new_row + d[0]
                    capture_col = new_col + d[1]

                    if self.is_valid_position(capture_row, capture_col) and not self.board[capture_row, capture_col]:
                        valid_moves.append((capture_row, capture_col))

        return valid_moves

    def is_valid_position(self, row, col):
        # Check if a position is within the board
        return 0 <= row < 8 and 0 <= col < 8


class Piece:
    def __init__(self, color, position):
        self.color = color
        self.position = position
        self.symbol = 'w' if color == "white" else 'b'
        self.king_status = False

    def update_position(self, row, col):
        # Update the piece's position
        self.row = row
        self.col = col

    def king(self):
        # King the piece
        self.symbol = 'W' if self.color == "white" else 'B'
        self.king_status = True


if __name__ == "__main__":
    board = Board()
    board.print_board()
